class Solution:
    def parseBoolExpr(self, expression: str) -> bool:
        def parse(expr):
            if expr == 't':
                return True
            elif expr == 'f':
                return False
            elif expr[0] == '!':
                return not parse(expr[2:-1])
            elif expr[0] == '&':
                return all(parse(e) for e in expr[2:-1].split(','))
            elif expr[0] == '|':
                return any(parse(e) for e in expr[2:-1].split(','))

        def find_matching_paren(s, start):
            count = 0
            for i in range(start, len(s)):
                if s[i] == '(':
                    count += 1
                elif s[i] == ')':
                    count -= 1
                if count == 0:
                    return i

        def recursive_parse(expr):
            if expr[0] in ['t', 'f']:
                return expr
            elif expr[0] == '!':
                end = find_matching_paren(expr, 1)
                return '!' + recursive_parse(expr[1:end])
            elif expr[0] in ['&', '|']:
                end = find_matching_paren(expr, 0)
                sub_exprs = expr[2:end].split(',')
                sub_exprs = [recursive_parse(se) for se in sub_exprs]
                return expr[0] + '(' + ','.join(sub_exprs) + ')'

        expr = recursive_parse(expression)
        return parse(expr)
