class Solution:
    def parseBoolExpr(self, expression: str) -> bool:
        def parse(expr):
            if expr == 't':
                return True
            elif expr == 'f':
                return False
            elif expr[0] == '!':
                return not parse(expr[2:-1])
            elif expr[0] == '&':
                return all(parse(e) for e in expr[2:-1].split(','))
            elif expr[0] == '|':
                return any(parse(e) for e in expr[2:-1].split(','))

        def helper(index):
            if expression[index] == 't' or expression[index] == 'f':
                return index + 1, expression[index] == 't'
            elif expression[index] == '!':
                index, value = helper(index + 2)
                return index + 1, not value
            elif expression[index] == '&':
                index, values = index + 2, []
                while expression[index] != ')':
                    index, value = helper(index)
                    values.append(value)
                    if expression[index] == ',':
                        index += 1
                return index + 1, all(values)
            elif expression[index] == '|':
                index, values = index + 2, []
                while expression[index] != ')':
                    index, value = helper(index)
                    values.append(value)
                    if expression[index] == ',':
                        index += 1
                return index + 1, any(values)

        return helper(0)[1]
