from typing import List

class Solution:
    def makeArrayIncreasing(self, arr1: List[int], arr2: List[int]) -> int:
        arr2.sort()
        memo = {}

        def dp(i, prev):
            if i == len(arr1):
                return 0
            if (i, prev) in memo:
                return memo[(i, prev)]
            res = float('inf')
            if arr1[i] > prev:
                res = dp(i + 1, arr1[i])
            j = self.binary_search(arr2, prev)
            if j < len(arr2) and arr2[j] > prev:
                res = min(res, 1 + dp(i + 1, arr2[j]))
            memo[(i, prev)] = res
            return res

        res = dp(0, -1)
        return res if res != float('inf') else -1

    def binary_search(self, arr, target):
        left, right = 0, len(arr) - 1
        while left <= right:
            mid = (left + right) // 2
            if arr[mid] > target:
                right = mid - 1
            else:
                left = mid + 1
        return left
